create table dirkspzm32.isi_res_magazin (
    sid       varchar2(2 char) not null enable,
    firma_nr  number(6, 0) not null enable,
    res_id    number(*, 0) not null enable,
    ma_res_id number(*, 0) not null enable
);

alter table dirkspzm32.isi_res_magazin
    add constraint pk_res_magazin
        primary key ( res_id,
                      ma_res_id,
                      firma_nr,
                      sid )
            using index enable;


